# Patch: clear demo data, expand serial DB, accept unknown serials
# Run: Set-ExecutionPolicy Bypass -Scope Process -Force; .\PATCHUI.ps1

$RepoPath = "C:\Users\LionelMosley\Documents\HTML\Synology - DiskStation Monitor"
Set-Location $RepoPath
Write-Host "Patching dashboard..." -ForegroundColor Cyan

$b64 = ""
$bytes = [System.Convert]::FromBase64String($b64)
$fullPath = Join-Path $RepoPath "frontend\public\synology-monitor.html"
[System.IO.File]::WriteAllBytes($fullPath, $bytes)
Write-Host "  patched" -ForegroundColor Green

git add frontend/public/synology-monitor.html
git commit -m "fix: clear demo devices, expand serial DB, accept unknown serials"
git push origin main

if ($LASTEXITCODE -eq 0) {
    Write-Host "`n Done! Refresh dashboard - fleet will be empty, serial lookup now works." -ForegroundColor Green
} else {
    Write-Host "`n Push failed." -ForegroundColor Red
}
